+        let mut reordered_levels = vec![Level(NO_LEVEL); reordered.len()];
+
+        for (vis_idx, &log_idx) in reordered.iter().enumerate() {
+            reordered_levels[vis_idx] = levels[log_idx];
+        }
+
+        reordered_levels.retain(|l| !l.removed_by_x9());
