+                let start = reordered[idx_range.clone()].iter().min().unwrap();
+                let end = reordered[idx_range.clone()].iter().max().unwrap();
+                runs.push(ReorderedRun {
+                    direction: level.direction(),
+                    level,
+                    range: *start..*end + 1,
+                    indices: reordered[idx_range].to_vec(),
