+            Tree::Leaf(left) => Ok(Self {
+                it: Box::new(Tree::Node {
+                    data: None,
+                    left: Box::new(Tree::Leaf(left)),
+                    right: Box::new(Tree::Leaf(right)),
+                }),
+                path: self.path,
+            }),
+            _ => Err(self),
