+    let mut data = vec![0u8; data_len];
+    r.read_exact(&mut data).await.with_context(|| {
+        format!(
+            "decode_raw_async failed to read {} bytes of data \
+            for PDU of length {} with serial={} ident={}",
+            data_len, len, serial, ident
+        )
+    })?;
+    Ok(Decoded {
+        ident,
+        serial,
+        data,
+        is_compressed,
+    })
+}
