+                // Unset the hyperlink on the cell, if any, and record that
+                // in the hyperlinks data for later restoration.
+                if let Some(link) = cell.attrs_mut().hyperlink().map(Arc::clone) {
+                    cell.attrs_mut().set_hyperlink(None);
