+    pub fn from_named(name: &str) -> Option<Self> {
+        #[cfg(feature = "std")]
+        {
+            return NAMED_COLORS.get(&name.to_ascii_lowercase()).cloned();
+        }
+        #[cfg(not(feature = "std"))]
+        {
+            let mut result = None;
+            iter_rgb_txt(|candidate, color| {
+                if candidate.eq_ignore_ascii_case(name) {
+                    result.replace(color);
+                    true
+                } else {
+                    false
