+impl Palette {
+    pub fn overlay_with(&self, other: &Self) -> Self {
+        macro_rules! overlay {
+            ($name:ident) => {
+                if let Some(c) = &other.$name {
+                    Some(c.clone())
+                } else {
+                    self.$name.clone()
+                }
+            };
+        }
+        Self {
+            foreground: overlay!(foreground),
+            background: overlay!(background),
+            cursor_fg: overlay!(cursor_fg),
+            cursor_bg: overlay!(cursor_bg),
