+struct ConfigInner {
+    config: Arc<Config>,
+    error: Option<String>,
+    warnings: Vec<String>,
+    generation: usize,
+    watcher: Option<notify::RecommendedWatcher>,
+    subscribers: HashMap<usize, Box<dyn Fn() -> bool + Send>>,
