+
+impl ConfigInner {
+    fn new() -> Self {
+        Self {
+            config: Arc::new(Config::default_config()),
+            error: None,
+            warnings: vec![],
+            generation: 0,
+            watcher: None,
+            subscribers: HashMap::new(),
