+    /// Attempt to load the user's configuration.
+    /// On success, clear any error and replace the current
+    /// configuration.
+    /// On failure, retain the existing configuration but
+    /// replace any captured error message.
+    fn reload(&mut self) {
+        let LoadedConfig {
+            config,
+            file_name,
+            lua,
+            warnings,
+        } = Config::load();
