+impl AsRawHandle for OwnedHandle {
+    fn as_raw_handle(&self) -> RawHandle {
+        self.handle
+    }
+}
+
+impl IntoRawHandle for OwnedHandle {
+    fn into_raw_handle(self) -> RawHandle {
+        let handle = self.handle;
+        std::mem::forget(self);
+        handle
+    }
+}
